#include <bits/stdc++.h>
using namespace std;
const int N=200005;
map<int,int> mp;
int a[N],b[N],n,_gcd=0;
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		mp[a[i]]=i;
	}
	for(int i=1;i<=n;i++)
	{
		cin>>b[i];
		_gcd=__gcd(_gcd,abs(i-mp[b[i]]));
	}
	for(int i=1;i<=_gcd;i++)
	{
		if(_gcd%i==0) cout<<i<<'\n';
	}
	return 0;
}
